        /// <summary>
        /// Returns the translation for <paramref name="keyId"/> in <paramref name="language"/>,
        /// or an empty string when it is missing. When <paramref name="values"/> is supplied the
        /// text is rendered through SmartFormat; otherwise the raw text is returned.
        /// </summary>
        public static string Get(string language, Guid keyId, IDictionary<string, object>? values = null)
        {
            if (!Translations.TryGetValue(language, out Dictionary<Guid, string>? langMap) || langMap == null)
                return string.Empty;
            if (!langMap.TryGetValue(keyId, out string? text) || text == null)
                return string.Empty;
            return values == null ? text : Smart.Format(text, values);
        }
    }
